下面是一个简单的智能合约实现，以实现TKL代币的发行、质押和TKvote代币的授予。

```solidity
pragma solidity ^0.8.0;

contract TKLContract {
    string public name;
    string public symbol;
    uint256 public totalSupply;

    mapping(address => uint256) public balanceOf;
    mapping(address => uint256) public lockedBalance;
    mapping(address => uint256) public timeLocked;

    mapping(address => uint256) public tkVoteBalance;

    event Transfer(address indexed from, address indexed to, uint256 value);
    event Approval(address indexed owner, address indexed spender, uint256 value);

    constructor() {
        name = "TKL Token";
        symbol = "TKL";
        totalSupply = 1000000000;

        // 发行所有的代币
        balanceOf[msg.sender] = totalSupply;
    }

    function transfer(address _to, uint256 _value) public returns (bool success) {
        require(_to != address(0), "Invalid recipient address");
        require(_value <= balanceOf[msg.sender], "Insufficient balance");

        balanceOf[msg.sender] -= _value;
        balanceOf[_to] += _value;

        emit Transfer(msg.sender, _to, _value);
        return true;
    }

    function approve(address _spender, uint256 _value) public returns (bool success) {
        require(_spender != address(0), "Invalid spender address");

        tkVoteBalance[_spender] += _value;

        emit Approval(msg.sender, _spender, _value);
        return true;
    }

    function transferFrom(address _from, address _to, uint256 _value) public returns (bool success) {
        require(_from != address(0), "Invalid sender address");
        require(_to != address(0), "Invalid recipient address");
        require(_value <= balanceOf[_from], "Insufficient balance");
        require(_value <= tkVoteBalance[_from], "Insufficient TKvote balance");

        balanceOf[_from] -= _value;
        balanceOf[_to] += _value;

        tkVoteBalance[_from] -= _value;

        emit Transfer(_from, _to, _value);
        return true;
    }

    function lockTokens(uint256 _value, uint256 _lockDuration) public returns (bool success) {
        require(_value <= balanceOf[msg.sender], "Insufficient balance");
        require(_value >= 10000, "Minimum lock amount is 10000 TKL");

        balanceOf[msg.sender] -= _value;
        lockedBalance[msg.sender] += _value;
        timeLocked[msg.sender] = block.timestamp + _lockDuration;

        emit Transfer(msg.sender, address(this), _value);
        return true;
    }

    function unlockTokens() public {
        require(lockedBalance[msg.sender] > 0, "No locked balance");

        if (block.timestamp >= timeLocked[msg.sender]) {
            balanceOf[msg.sender] += lockedBalance[msg.sender];
            emit Transfer(address(this), msg.sender, lockedBalance[msg.sender]);
            lockedBalance[msg.sender] = 0;
            timeLocked[msg.sender] = 0;
        }
    }
}
```

这个智能合约实现了以下功能：
- 发行了名为 "TKL Token" 的代币，代号为 "TKL"，总发行量为10亿。
- 实现了代币的转账功能，通过 `transfer` 函数。
- 实现了代币的授权功能，通过 `approve` 函数。
- 实现了从授权额度中转账的功能，通过 `transferFrom` 函数。
- 实现了代币的锁定和解锁功能，通过 `lockTokens` 和 `unlockTokens` 函数。
- 用户可以调用 `lockTokens` 来锁定>=10000个TKL代币，并设置锁定期限。
- 当锁定期限结束时，用户可以调用 `unlockTokens` 来解锁代币。

您可以在此基础上扩展您的选举投票功能，例如根据质押的TKL代币数量，授予相应数量的TKvote代币，并在智能合约中记录选举投票的相关数据。

下面是一个基于以太坊的智能合约实现，实现您所描述的质押10000个代币一年获得一枚选举代币的功能。

```solidity
pragma solidity ^0.8.0;

contract ElectionContract {
    string public name;
    string public symbol;
    uint256 public totalSupply;

    // 存储用户的代币余额
    mapping(address => uint256) public balanceOf;
    // 存储用户质押的代币数量
    mapping(address => uint256) public stakedBalance;
    // 存储用户质押的开始时间
    mapping(address => uint256) public stakeStartTime;

    // 存储选举代币余额
    mapping(address => uint256) public voteBalance;

    event Transfer(address indexed from, address indexed to, uint256 value);
    event Approval(address indexed owner, address indexed spender, uint256 value);
    event Staked(address indexed staker, uint256 value);
    event Unstaked(address indexed staker, uint256 value);
    event VoteCasted(address indexed voter, address indexed candidate, uint256 voteCount);

    constructor() {
        name = "TKL Token";
        symbol = "TKL";
        totalSupply = 1000000000;
        balanceOf[msg.sender] = totalSupply;
    }

    function transfer(address _to, uint256 _value) public returns (bool success) {
        require(_to != address(0), "Invalid recipient address");
        require(_value <= balanceOf[msg.sender], "Insufficient balance");

        balanceOf[msg.sender] -= _value;
        balanceOf[_to] += _value;

        emit Transfer(msg.sender, _to, _value);
        return true;
    }

    function approve(address _spender, uint256 _value) public returns (bool success) {
        require(_spender != address(0), "Invalid spender address");

        voteBalance[_spender] += _value;

        emit Approval(msg.sender, _spender, _value);
        return true;
    }

    function transferFrom(address _from, address _to, uint256 _value) public returns (bool success) {
        require(_from != address(0), "Invalid sender address");
        require(_to != address(0), "Invalid recipient address");
        require(_value <= balanceOf[_from], "Insufficient balance");
        require(_value <= voteBalance[_from], "Insufficient vote balance");

        balanceOf[_from] -= _value;
        balanceOf[_to] += _value;

        voteBalance[_from] -= _value;

        emit Transfer(_from, _to, _value);
        return true;
    }

    function stakeTokens(uint256 _amount) public {
        require(_amount <= balanceOf[msg.sender], "Insufficient balance");

        balanceOf[msg.sender] -= _amount;
        stakedBalance[msg.sender] += _amount;
        stakeStartTime[msg.sender] = block.timestamp;

        emit Staked(msg.sender, _amount);
    }

    function unstakeTokens() public {
        require(stakedBalance[msg.sender] > 0, "No staked balance");

        uint256 stakedAmount = stakedBalance[msg.sender];
        balanceOf[msg.sender] += stakedAmount;
        stakedBalance[msg.sender] = 0;
        stakeStartTime[msg.sender] = 0;

        emit Unstaked(msg.sender, stakedAmount);
    }

    function castVote(address _candidate, uint256 _voteCount) public {
        require(voteBalance[msg.sender] >= _voteCount, "Insufficient vote balance");

        voteBalance[msg.sender] -= _voteCount;

        emit VoteCasted(msg.sender, _candidate, _voteCount);
    }

    function calculateVoteReward(address _voter) public view returns (uint256) {
        uint256 stakedAmount = stakedBalance[_voter];
        uint256 stakesTime = block.timestamp - stakeStartTime[_voter];

        if (stakedAmount >= 10000 && stakesTime >= 365 days) {
            return 1;
        } else {
            return 0;
        }
    }
}
```

这个智能合约实现了以下功能：
- 发行了名为 "TKL Token" 的代币，代号为 "TKL"，总发行量为10亿。
- 实现了代币的转账功能，通过 `transfer` 函数。
- 实现了代币的授权功能，通过 `approve` 函数。
- 实现了从授权额度中转账的功能，通过 `transferFrom` 函数。
- 实现了代币的质押和解质押功能，通过 `stakeTokens` 和 `unstakeTokens` 函数。
- 实现了选举投票功能，通过 `castVote` 函数。
- 提供了一个计算投票奖励的函数 `calculateVoteReward`，用户可以调用该函数来计算给定地址的投票奖励。

根据您的经济模型，当用户质押的代币数量达到10000并且质押时间超过365天时，他们将获得1枚投票代币。您可以根据需要对此实现进行扩展和定制。

下面是一个简单的双代币模型的智能合约实现，包括一个主代币和一个辅助代币。

```solidity
pragma solidity ^0.8.0;

contract DualTokenContract {
    string public mainTokenName;
    string public mainTokenSymbol;
    uint256 public mainTokenTotalSupply;

    string public auxiliaryTokenName;
    string public auxiliaryTokenSymbol;
    uint256 public auxiliaryTokenTotalSupply;

    mapping(address => uint256) public mainTokenBalanceOf;
    mapping(address => uint256) public auxiliaryTokenBalanceOf;

    event TransferMainToken(address indexed from, address indexed to, uint256 value);
    event TransferAuxiliaryToken(address indexed from, address indexed to, uint256 value);

    constructor(
        string memory _mainTokenName,
        string memory _mainTokenSymbol,
        uint256 _mainTokenTotalSupply,
        string memory _auxiliaryTokenName,
        string memory _auxiliaryTokenSymbol,
        uint256 _auxiliaryTokenTotalSupply
    ) {
        mainTokenName = _mainTokenName;
        mainTokenSymbol = _mainTokenSymbol;
        mainTokenTotalSupply = _mainTokenTotalSupply;

        auxiliaryTokenName = _auxiliaryTokenName;
        auxiliaryTokenSymbol = _auxiliaryTokenSymbol;
        auxiliaryTokenTotalSupply = _auxiliaryTokenTotalSupply;

        mainTokenBalanceOf[msg.sender] = mainTokenTotalSupply;
        auxiliaryTokenBalanceOf[msg.sender] = auxiliaryTokenTotalSupply;
    }

    function transferMainToken(address _to, uint256 _value) public returns (bool success) {
        require(_to != address(0), "Invalid recipient address");
        require(_value <= mainTokenBalanceOf[msg.sender], "Insufficient main token balance");

        mainTokenBalanceOf[msg.sender] -= _value;
        mainTokenBalanceOf[_to] += _value;

        emit TransferMainToken(msg.sender, _to, _value);
        return true;
    }

    function transferAuxiliaryToken(address _to, uint256 _value) public returns (bool success) {
        require(_to != address(0), "Invalid recipient address");
        require(_value <= auxiliaryTokenBalanceOf[msg.sender], "Insufficient auxiliary token balance");

        auxiliaryTokenBalanceOf[msg.sender] -= _value;
        auxiliaryTokenBalanceOf[_to] += _value;

        emit TransferAuxiliaryToken(msg.sender, _to, _value);
        return true;
    }
}
```

这个智能合约实现了以下功能：
- 创建了两个代币：一个主代币和一个辅助代币。
- 主代币有名称、符号和总供应量，并将初始供应量分配给合约创建者。
- 辅助代币也有名称、符号和总供应量，并将初始供应量分配给合约创建者。
- 实现了主代币的转账功能，通过 `transferMainToken` 函数。
- 实现了辅助代币的转账功能，通过 `transferAuxiliaryToken` 函数。
- 使用映射来记录每个地址的主代币和辅助代币余额。
- 通过事件 `TransferMainToken` 和 `TransferAuxiliaryToken` 在转账时触发事件。

您可以根据需要在此基础上构建更复杂的双代币模型，并添加其他功能和规则，如质押、挖矿、奖励等。

